const appliedIds = new Set(
  ($('Get Applied Job IDs').all()[0]?.json?.items || []).map(i => String(i['Job ID'] || '').trim()).filter(Boolean)
);

const j = $input.item.json;
const jobId = String(j.id || '').trim();

if (appliedIds.has(jobId)) {
  return []; // Skip if duplicate
}

try {
  const title = String(j.title || '').toLowerCase();
  const seniority = String(j.seniorityLevel || '').toLowerCase();
  const funcs = Array.isArray(j.jobFunctions)
    ? j.jobFunctions.join(' ').toLowerCase()
    : String(j.jobFunctions || '').toLowerCase();

  const desc = String(j.descriptionHtml || '')
    .replace(/<[^>]*>/g, ' ')
    .toLowerCase();

  const goodTitle = /(intern|internship|co-op|coop|student)/.test(title);

  const badTitle = /(sales|marketing|account executive|nurse|customer service|recruiter|insurance advisor|financial advisor|cashier)/.test(title);

  const seniorBad =
    /(senior|staff|principal|manager|director|lead)/.test(seniority) ||
    /(manager|director|lead)/.test(title);

  const techSignals =
    (title + ' ' + funcs + ' ' + desc).match(
      /python|java|javascript|typescript|sql|api|cloud|aws|azure|gcp|automation|backend|react|node|ai|machine learning|data|qa|testing|it support/g
    ) || [];

  const cheapPass = goodTitle && !badTitle && !seniorBad && techSignals.length >= 1;

  const website = String(j.companyWebsite || '').trim();
  const domain = website
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .split('/')[0]
    .trim();

  return {
    json: {
      ...j,
      cheapPass: cheapPass,
      techSignalCount: techSignals.length,
      company_domain: domain,
      decision_maker_category: ['engineering', 'it', 'hr']
    }
  };
} catch (e) {
  return [];
}

const job = $('Evaluate Job').item.json;
const title = job.title || 'the open role';
const company = job.companyName || 'your company';

const allSkills = /python|java|javascript|typescript|sql|api|cloud|aws|azure|gcp|automation|backend|react|node|ai|machine learning|data|qa|testing|it support/gi;
const desc = String(job.descriptionHtml || '').replace(/<[^>]*>/g, ' ').toLowerCase();
const funcs = Array.isArray(job.jobFunctions) ? job.jobFunctions.join(' ').toLowerCase() : String(job.jobFunctions || '').toLowerCase();
const fullText = (title + ' ' + funcs + ' ' + desc).toLowerCase();

const matchedSkills = fullText.match(allSkills) || [];
const uniqueSkills = [...new Set(matchedSkills)].slice(0, 3);
const skillsText = uniqueSkills.length > 0 ? Object.keys(uniqueSkills).length > 1 ? 'specialized experience in ' + uniqueSkills.slice(0, -1).join(', ') + ' and ' + uniqueSkills[uniqueSkills.length-1] : 'robust background in ' + uniqueSkills[0] : 'a solid foundation in technology';

const objective = `PROFESSIONAL SUMMARY\nEnthusiastic and results-driven Computer Science student at Algoma University, actively seeking the ${title} opportunity at ${company}. Combining ${skillsText} with a proven ability to build automated systems and solve complex problems, I am eager to contribute immediately to your team's success while continuing to grow as a technical professional.\n\n`;

return {
  json: {
    customized_summary: objective
  }
};

const result = $('Get Company Emails').item.json;

// Support both /search/company response shapes
const emails = result.emails || [];
const persons = result.persons || [];

// Build combined list
const contacts = emails.map((email, i) => {
  const person = persons[i] || {};
  return {
    email: email,
    name: person.full_name || person.name || ''
  };
}).filter(c => c.email);

// Fallback to single email fields if needed
if (contacts.length === 0) {
  const singleEmail = result.valid_email || result.email || '';
  const singleName = result.person_full_name || '';
  if (singleEmail) contacts.push({ email: singleEmail, name: singleName });
}

const toEmail = contacts[0]?.email || '';
const bccEmails = contacts.slice(1).map(c => c.email).join(',');
const allNames = contacts.map(c => c.name).filter(Boolean).join(', ');
const allEmails = contacts.map(c => c.email).join(', ');
const firstPersonName = contacts[0]?.name?.split(' ')[0] || 'there';

return {
  json: {
    toEmail,
    bccEmails,
    allNames,
    allEmails,
    firstPersonName,
    contactCount: contacts.length
  }
};
